import time
from enum import Enum

class BreakerState(Enum):
    CLOSED = 'closed'       # normal operation
    OPEN = 'open'           # tripped -- agent is paused
    HALF_OPEN = 'half_open' # testing if recovery is possible

class CircuitBreaker:
    def __init__(self, failure_threshold=5, recovery_timeout=60):
        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout  # seconds before trying again
        self.state = BreakerState.CLOSED
        self.failure_count = 0
        self.last_failure_time = None

    def call(self, fn, *args, **kwargs):
        if self.state == BreakerState.OPEN:
            elapsed = time.time() - (self.last_failure_time or 0)
            if elapsed >= self.recovery_timeout:
                self.state = BreakerState.HALF_OPEN
                print('Circuit half-open: testing recovery')
            else:
                raise RuntimeError('Circuit breaker OPEN -- action blocked')

        try:
            result = fn(*args, **kwargs)
            self._on_success()
            return result
        except Exception as e:
            self._on_failure()
            raise

    def _on_success(self):
        self.failure_count = 0
        self.state = BreakerState.CLOSED

    def _on_failure(self):
        self.failure_count += 1
        self.last_failure_time = time.time()
        if self.failure_count >= self.failure_threshold:
            self.state = BreakerState.OPEN
            print('Circuit OPEN after ' + str(self.failure_count) + ' failures')

# Wrap every autonomous action with a circuit breaker
breaker = CircuitBreaker(failure_threshold=3, recovery_timeout=120)

def risky_action(x):
    if x < 0:
        raise ValueError('Invalid input: ' + str(x))
    return x * 2

for i in [1, -1, -1, -1, 2]:  # three failures will trip the breaker
    try:
        result = breaker.call(risky_action, i)
        print('Result:', result)
    except RuntimeError as e:
        print('Blocked:', e)
    except ValueError as e:
        print('Action failed:', e)
